42	const PROCESSING_FEE = 5;
43	const CURSED_SURCHARGE_RATE = 0.5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
47	const LOYALTY_DISCOUNT_RATE = 0.2;
48	const LOYALTY_THRESHOLD_YEARS = 2;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	
51	const DEDUCTIBLE = 100;
52	
53	const INSURANCE_VALUES: Record<string, number> = {
54	  sword: 1000,
55	  amulet: 600,
56	  staff: 800,
57	  potion: 400,
58	  rune: 250,
59	  moonstone: 250,
60	};
61	
62	const BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	  moonstone: 25,
69	};
70	
71	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
72	const BLOCK_SIZE = 3;
73	const BLOCK_PREMIUM = 60;
74	
75	const calculateComponentPremium = (type: string, count: number): number =>
76	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
77	
78	const calculateItemPremium = (item: Item): number => {
79	  const base = BASE_PREMIUMS[item.type] ?? 0;
80	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
81	  const enchantmentSurcharge =
82	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
83	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
84	      : 0;
85	  return base + cursedSurcharge + enchantmentSurcharge;
86	};
87	
88	const calculatePremiums = (items: Item[]): { basePremiumTotal: number; totalWithSurcharges: number } => {
89	  const componentCounts = new Map<string, number>();
90	  let basePremiumTotal = 0;
91	  let totalWithSurcharges = 0;
92	
93	  for (const item of items) {
94	    if (COMPONENT_TYPES.has(item.type)) {
95	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
96	    } else {
97	      basePremiumTotal += BASE_PREMIUMS[item.type] ?? 0;
98	      totalWithSurcharges += calculateItemPremium(item);
99	    }
100	  }
101	
102	  for (const [type, count] of componentCounts) {
103	    const componentPremium = calculateComponentPremium(type, count);
104	    basePremiumTotal += componentPremium;
105	    totalWithSurcharges += componentPremium;
106	  }
107	
108	  return { basePremiumTotal, totalWithSurcharges };
109	};
